mapper.select:
SELECT ID, AGENT_NAME, INTRODUCTION, AVATAR, STATUS, API_KEY, AGENT_SORT, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, TYPE,AGENT_CODE FROM SYS_AGENT
AND AGENT_NAME LIKE #{agentNameLike}
AND STATUS = #{status}
ORDER BY AGENT_SORT, ID

mapper.update:
UPDATE SYS_AGENT
SET AGENT_NAME = #{agentName}, INTRODUCTION = #{introduction}, AVATAR = #{avatar},
    STATUS = #{status}, API_KEY = #{apiKey}, AGENT_SORT = #{agentSort},
    UPDATE_BY = #{updateBy}, UPDATE_BY_NAME = #{updateByName}, UPDATE_TIME = #{updateTime},
    TYPE = #{type},AGENT_CODE=#{agentCode}
WHERE ID = #{id}

